// Find chapters that have NO rows yet in content_plan.
// A chapter is identified by drive_file_id + chapter_number.
const manifest = $items('Read Manifest').map(i => i.json);
const plan = $items('Read Content Plan').map(i => i.json);

// Set of already-planned chapter keys
const plannedKeys = new Set(
  plan
    .filter(r => r.drive_file_id && (r.chapter_number !== undefined && r.chapter_number !== ''))
    .map(r => `${r.drive_file_id}::${r.chapter_number}`)
);

const toPlan = [];
for (const book of manifest) {
  if (book.status !== 'active') continue;
  let chapters = [];
  try { chapters = JSON.parse(book.chapter_boundaries_json || '[]'); } catch (e) { continue; }
  for (const ch of chapters) {
    const key = `${book.drive_file_id}::${ch.chapter_number}`;
    if (plannedKeys.has(key)) continue;
    toPlan.push({
      drive_file_id: book.drive_file_id,
      book_title: book.title,
      book_author: book.author,
      chapter_number: ch.chapter_number,
      chapter_title: ch.chapter_title,
      start_page: ch.start_page,
      end_page: ch.end_page
    });
  }
}

if (toPlan.length === 0) {
  return [{ json: { _empty: true, message: 'All chapters already planned.' } }];
}
return toPlan.map(c => ({ json: c }));

const raw = $json.text || $json.data || '';
let pages = [];
if (Array.isArray(raw)) pages = raw;
else if (typeof raw === 'string') {
  pages = raw.split('\f');
  if (pages.length < 3) pages = raw.split(/\n\s*\n\s*\n/);
}
const ctx = $('Loop Each Chapter').item.json;
const start = Math.max(0, (ctx.start_page || 1) - 1);
const end = Math.min(pages.length, ctx.end_page || pages.length);
const chapterText = pages.slice(start, end).join('\n\n').slice(0, 30000);
return [{ json: { ...ctx, chapter_text: chapterText, chapter_char_count: chapterText.length } }];

const raw = $json.output || '';
const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
let parsed;
try { parsed = JSON.parse(cleaned); } catch (e) {
  throw new Error('Planner returned invalid JSON: ' + e.message + ' | raw: ' + raw.slice(0, 300));
}
const concepts = parsed.concepts || [];
const ctx = $('Slice To Chapter').item.json;
if (concepts.length === 0) {
  // Still emit one row so the chapter is not re-planned forever
  return [{
    json: {
      drive_file_id: ctx.drive_file_id,
      book_title: ctx.book_title,
      book_author: ctx.book_author,
      chapter_number: ctx.chapter_number,
      chapter_title: ctx.chapter_title,
      start_page: ctx.start_page,
      end_page: ctx.end_page,
      concept_index: 0,
      concept_title: '(no usable concept)',
      angle: '',
      brief: '',
      richness: 'chapter yielded nothing',
      status: 'skipped',
      planned_at: new Date().toISOString()
    }
  }];
}
return concepts.map(c => ({
  json: {
    drive_file_id: ctx.drive_file_id,
    book_title: ctx.book_title,
    book_author: ctx.book_author,
    chapter_number: ctx.chapter_number,
    chapter_title: ctx.chapter_title,
    start_page: ctx.start_page,
    end_page: ctx.end_page,
    concept_index: c.concept_index,
    concept_title: c.concept_title,
    angle: c.angle,
    brief: c.brief,
    richness: c.richness || '',
    status: 'planned',
    planned_at: new Date().toISOString()
  }
}));
